changeSet.sql:
ALTER TABLE tasks ADD COLUMN name character varying (255) DEFAULT NULL;
CREATE INDEX i_tasks_name ON tasks (name, organization_id);

ALTER TABLE tasks ADD COLUMN task_assignee_id integer DEFAULT NULL;
CREATE INDEX i_tasks_task_assignee ON tasks (task_assignee_id);
ALTER TABLE tasks ADD CONSTRAINT fk_tasks_to_task_assignee_user FOREIGN KEY (task_assignee_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE;
